let rawA = $.steps.fetchDatasetA.output || '';
let rawB = $.steps.fetchDatasetB.output || '';
rawA = rawA.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
rawB = rawB.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
let dataA, dataB;
try { dataA = JSON.parse(rawA); } catch(e) { dataA = []; }
try { dataB = JSON.parse(rawB); } catch(e) { dataB = []; }
if (!Array.isArray(dataA)) dataA = [dataA];
if (!Array.isArray(dataB)) dataB = [dataB];
return { dataA, dataB, countA: dataA.length, countB: dataB.length };

const { dataA, dataB } = $.steps.parseDatasets.output;
const joinParts = ($.input.joinKey || 'id:id').split(':');
const keyA = joinParts[0].trim();
const keyB = (joinParts[1] || joinParts[0]).trim();

// Build index on dataset B
const indexB = {};
dataB.forEach(item => {
  const key = String(item[keyB] || '');
  if (!indexB[key]) indexB[key] = [];
  indexB[key].push(item);
});

// Inner join: items from A that have matching items in B
const innerJoin = [];
dataA.forEach(a => {
  const key = String(a[keyA] || '');
  const matches = indexB[key] || [];
  matches.forEach(b => {
    innerJoin.push({ ...a, _joined: b });
  });
});

// Left join: all items from A, with B data if matched
const leftJoin = [];
dataA.forEach(a => {
  const key = String(a[keyA] || '');
  const matches = indexB[key] || [];
  if (matches.length > 0) {
    matches.forEach(b => { leftJoin.push({ ...a, _joined: b, _matched: true }); });
  } else {
    leftJoin.push({ ...a, _joined: null, _matched: false });
  }
});

// Union: all items from both datasets
const union = [...dataA.map(a => ({ _source: 'A', ...a })), ...dataB.map(b => ({ _source: 'B', ...b }))];

// Only in A (not in B)
const onlyA = dataA.filter(a => {
  const key = String(a[keyA] || '');
  return !indexB[key];
});

return {
  innerJoin: innerJoin.slice(0, 20),
  leftJoin: leftJoin.slice(0, 20),
  union: union.slice(0, 20),
  onlyA: onlyA.slice(0, 10),
  stats: {
    datasetA: dataA.length,
    datasetB: dataB.length,
    innerJoinCount: innerJoin.length,
    leftJoinCount: leftJoin.length,
    unionCount: union.length,
    onlyInA: onlyA.length,
    joinKeyA: keyA,
    joinKeyB: keyB
  }
};

const m = $.steps.mergeDatasets.output;
const s = m.stats;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Dataset Merge Results' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Sources*\nDataset A: `' + $.input.apiUrlA + '` (' + s.datasetA + ' items)\nDataset B: `' + $.input.apiUrlB + '` (' + s.datasetB + ' items)\nJoin key: `' + s.joinKeyA + '` = `' + s.joinKeyB + '`' } });
blocks.push({ type: 'divider' });

// Stats fields
const fields = [
  { type: 'mrkdwn', text: '*Inner Join*\n' + s.innerJoinCount + ' rows' },
  { type: 'mrkdwn', text: '*Left Join*\n' + s.leftJoinCount + ' rows' },
  { type: 'mrkdwn', text: '*Union All*\n' + s.unionCount + ' rows' },
  { type: 'mrkdwn', text: '*Only in A*\n' + s.onlyInA + ' rows' }
];
blocks.push({ type: 'section', fields: fields.slice(0, 2) });
blocks.push({ type: 'section', fields: fields.slice(2, 4) });
blocks.push({ type: 'divider' });

// Inner join sample
if (m.innerJoin.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Inner Join Sample (first 3)*' } });
  m.innerJoin.slice(0, 3).forEach(row => {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '```' + JSON.stringify(row, null, 2).slice(0, 800) + '```' } });
  });
  blocks.push({ type: 'divider' });
}

// Only in A sample
if (m.onlyA.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Items Only in Dataset A (no match in B) — first 3*' } });
  m.onlyA.slice(0, 3).forEach(row => {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '```' + JSON.stringify(row, null, 2).slice(0, 500) + '```' } });
  });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Merged by One CLI Data Merger | Join key: ' + s.joinKeyA + ' = ' + s.joinKeyB }] });
return { blocks, fallback: 'Dataset Merge: ' + s.innerJoinCount + ' inner join rows from ' + s.datasetA + ' + ' + s.datasetB + ' items' };
